import { NavLink, useLocation } from 'react-router-dom';
import { usePortfolio } from '../contexts/PortfolioContext';
import { useUserProfile } from '../contexts/UserProfileContext';
import './Navbar.css';

export default function Navbar() {
  const { portfolioCount } = usePortfolio();
  const { isProfileComplete } = useUserProfile();
  const location = useLocation();

  const navLinks = [
    { to: '/',               label: 'Home'            },
    { to: '/products',       label: 'Products'        },
    { to: '/recommendations',label: 'For You'         },
    { to: '/profile',        label: 'Profile'         },
    { to: '/portfolio',      label: 'Portfolio'       },
  ];

  return (
    <nav className="navbar">
      <div className="navbar-inner container">
        <NavLink to="/" className="navbar-brand">
          <span className="brand-icon">◈</span>
          <span className="brand-name">Fin<span>Vault</span></span>
        </NavLink>

        <ul className="navbar-links">
          {navLinks.map(link => (
            <li key={link.to}>
              <NavLink
                to={link.to}
                end={link.to === '/'}
                className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}
              >
                {link.label}
                {link.to === '/portfolio' && portfolioCount > 0 && (
                  <span className="nav-badge">{portfolioCount}</span>
                )}
                {link.to === '/profile' && isProfileComplete() && (
                  <span className="nav-dot" />
                )}
              </NavLink>
            </li>
          ))}
        </ul>
      </div>
    </nav>
  );
}
